python
albums = [
    ("Orgy with the Dead", 2002),
    ("Tormentorium", 2003),
    ("7th Ritual for the Darkest Soul of Hell", 2008)
]

for title, year in albums:
    if "Torment" in title:
        print(f"'{title}' released in {year}")

The script will output: *Tormentorium released in 2003*.
